SELECT * FROM crosstab ( 'WITH data as ( select loc_id, uc_id, machine_id, (case when start_date< ''<<selected_start_date>>'' then ''<<selected_start_date>>'' else start_date end ) as start_date, -- (case -- when end_date>''<<selected_end_date>>'' then ''<<selected_end_date>>'' -- when end_date is null then -- (case -- when ''<<selected_end_date>>'' < NOW() then ''<<selected_end_date>>'' -- else NOW() -- end -- ) -- else end_date -- end -- ) as end_date, (case when lead(start_date,1) over (partition by machine_id order by start_date)>''<<selected_end_date>>'' then ''<<selected_end_date>>'' when lead(start_date,1) over (partition by machine_id order by start_date)<''<<selected_start_date>>'' then ''<<selected_start_date>>'' when lead(start_date,1) over (partition by machine_id order by start_date) is null then (case when ''<<selected_end_date>>'' < NOW() then ''<<selected_end_date>>'' else NOW() end) else lead(start_date,1) over (partition by machine_id order by start_date) end ) as end_date, act_status from transactions.machine_status as m where ( (end_date > ''<<selected_start_date>>'' and end_date > start_date) or end_date is null ) and ( start_date< ''<<selected_end_date>>'' ) and ( ''<<selected_start_date>>'' <NOW() ) and machine_id in (<<machineIdList>>) and loc_id = <<loc_id>> and uc_id = <<uc_id>>
)
select machine_id, act_status, coalesce(sum(EXTRACT(epoch FROM end_date::timestamp - start_date::timestamp )),0) from data group by machine_id, act_status order by machine_id asc, act_status asc', 'SELECT * FROM (VALUES (''1000''), (''1001''), (''1002''), (''1003''), (''1004''), (''1005'')) as act_status ORDER BY act_status asc' ) AS final_result(machine_id VARCHAR, "S1000" REAL,"S1001" REAL,"S1002" REAL, "S1003" REAL,"S1004" REAL,"S1005" REAL)


DELETE FROM transactions.rtmp_master_pic_relation 
WHERE   rtmp_master_id = [[parameter_id]]
RETURNING rtmp_master_id;

--========================================= -- QUERY TO DELETE DEL DUPLICATE DATA --=========================================
WITH same_data AS ( select id, machine_status_raw_id, machine_id, act_status, start_date, LAG(act_status,1) OVER ( PARTITION BY machine_id, loc_id, uc_id order by start_date ) next_act_status from transactions.machine_status WHERE start_date BETWEEN ([[start_date]]::timestamp - interval '1 hour') AND [[end_date]]::timestamp ) delete from transactions.machine_status where id in (select id from same_data where act_status = next_act_status and start_date BETWEEN [[start_date]]::timestamp AND [[end_date]]::timestamp);
--========================================= -- QUERY TO FIX END_DATE DATA AND CLOSE --========================================= WITH select_lead AS ( SELECT id, machine_status_raw_id, machine_id, act_status, start_date, LEAD(start_date,1) OVER ( PARTITION BY machine_id, loc_id, uc_id ORDER BY start_date ) next_start_date, LEAD(id,1) OVER ( PARTITION BY machine_id, loc_id, uc_id ORDER BY start_date ) next_id FROM transactions.machine_status WHERE start_date >= [[start_date]]::timestamp ) UPDATE transactions.machine_status ms SET end_date = sl.next_start_date, id_close = sl.next_id, duration = EXTRACT(EPOCH FROM sl.next_start_date - ms.start_date) FROM select_lead sl where ms.id = sl.id and ms.start_date BETWEEN [[start_date]]::timestamp AND [[end_date]]::timestamp;


