SELECT date_trunc('hour', day_start) AS open_date_ts,
to_char( date_trunc('hour', day_start), 'Mon DD HH12 AM' ) AS open_date,
SUM(total_used_energy) AS total_used_energy, SUM(total_tarrif) AS tarrif FROM transactions.energy_daily WHERE machine_id IN (<<machine_id>>) AND day_start >= ( [[start_date]] AT TIME ZONE current_setting('TIMEZONE') ) GROUP BY day_start ORDER BY day_start;


