/*
 * @name GetShiftPieChartDataForMachinesManagement
 * @date 28.06.2020
 * @author iSAX, Georg Reckendorfer
 * @param start			start date of the queried duration for the status query
 * @param end			end date of the queried duration for the status query
 * @param ListMachineIds	list of machine id´s for the queried sum of each status
 * @return infotable (HPMC.Asset.SingleStatus.Sum.DS) - sum for each status of the queried machineIds
 */
var loggerBeginning = "[HPMC.Database.MachineDB: LOGetShiftPieChartDataForMachinesManagement]: ";

logger.info(loggerBeginning + "Query sum of each status for the given machineIds in the duration of " + start + " to " + end);

var machineIds = "";
var tableLength = ListMachineIds.rows.length;

for (var x = 0; x < tableLength; x++) {
    machineIds += "'" + ListMachineIds.rows[x].element + "'";

    if (x < tableLength - 1) {
        machineIds += ", ";
    }
}

logger.info(loggerBeginning + "Query sum of each status for the given machineIds: " + machineIds);

result = me.LOGetShiftPieChartDataForMachines({
    machineIds: machineIds /* STRING */,
    start: start /* DATETIME */,
    end: end /* DATETIME */
});

