SELECT * FROM ( SELECT DISTINCT ON (asl.loc_id, asl.uc_id, asl.machine_id, asl.start_date, asl.end_date, asl.alarm_code) asl.machine_id, CASE WHEN asl.machine_status = '1000' THEN 'Idle' WHEN asl.machine_status = '1001' THEN 'Idle' WHEN asl.machine_status = '1002' THEN 'Running' WHEN asl.machine_status = '1003' THEN 'Running' WHEN asl.machine_status = '1004' THEN 'Down' WHEN asl.machine_status = '1005' THEN 'Idle' END AS machine_status, asl.alarm_type, asl.alarm_code, alm.alarm_description, asl.start_date FROM transactions.alarm_status_log AS asl INNER JOIN transactions.alarm_list_master AS alm ON asl.machine_id = alm.machine_id AND asl.loc_id = alm.loc_id AND asl.uc_id = alm.uc_id AND asl.alarm_code LIKE '%' || alm.alarm_code WHERE asl.start_date >= [[selectedStartDate]] AND asl.end_date < [[selectedEndDate]] AND asl.loc_id = [[locId]] AND asl.uc_id = [[ucId]] AND asl.machine_id IN (<<machineIdList>>) AND asl.alarm_type IN (<<alarmTypeList>>) AND asl.act_status = TRUE AND (EXTRACT(EPOCH FROM asl.end_date - asl.start_date)::float > 0 OR asl.duration IS NULL)
UNION
SELECT DISTINCT ON (efd.loc_id, efd.uc_id, efd.machine_id, efd.start_date, efd.end_date, efd.mode) efd.machine_id, CASE WHEN efd.machine_status = '1000' THEN 'Idle' WHEN efd.machine_status = '1001' THEN 'Idle' WHEN efd.machine_status = '1002' THEN 'Running' WHEN efd.machine_status = '1003' THEN 'Running' WHEN efd.machine_status = '1004' THEN 'Down' WHEN efd.machine_status = '1005' THEN 'Idle' END AS machine_status, alm.alarm_type, efd.mode AS alarm_code, alm.alarm_description, efd.start_date FROM transactions.emergency_functional_data AS efd INNER JOIN transactions.alarm_list_master AS alm ON efd.machine_id = alm.machine_id AND efd.loc_id = alm.loc_id AND efd.uc_id = alm.uc_id AND efd.mode = alm.alarm_code WHERE efd.start_date >= [[selectedStartDate]] AND efd.end_date < [[selectedEndDate]] AND efd.loc_id = [[locId]] AND efd.uc_id = [[ucId]] AND efd.machine_id IN (<<machineIdList>>) AND alm.alarm_type IN (<<alarmTypeList>>) AND (EXTRACT(EPOCH FROM efd.end_date - efd.start_date)::float > 0 OR efd.end_date IS NULL) ) AS total_alarm_list ORDER BY start_date, machine_id, alarm_code;

WITH -- 1. Generate a timeline of every minute between Start and End minute_series AS ( SELECT generate_series( [[startTime]]::timestamp, [[endTime]]::timestamp, '1 minute'::interval ) AS report_time ), -- 2. Get the list of target machines from your input target_machines AS ( SELECT DISTINCT machine_id FROM transactions.machine_status WHERE machine_id IN (<<machineId>>) ) SELECT tm.machine_id, -- Format the minute timestamp to_char(ms.report_time, 'Mon DD HH12:MI AM YYYY') AS created_at, ms.report_time AS original_start_date,
-- Data from the "Last Known" status record last_known.act_status, CASE WHEN last_known.act_status IN ('1002','1003') THEN 'Running' ELSE 'Not Running' END AS running_status, CASE WHEN last_known.act_status IN ('1002','1003') THEN 'running' WHEN last_known.act_status = '1001' THEN 'idle' WHEN last_known.act_status = '1004' THEN 'downtime' ELSE 'unknown' END AS machine_status
FROM minute_series ms CROSS JOIN target_machines tm LEFT JOIN LATERAL ( -- 3. KEY LOGIC: Find the most recent status record that happened ON or BEFORE this minute SELECT act_status FROM transactions.machine_status s WHERE s.machine_id = tm.machine_id AND s.start_date <= ms.report_time ORDER BY s.start_date DESC LIMIT 1 ) last_known ON true ORDER BY tm.machine_id, ms.report_time ASC;
